public class SortArray {
    public static void main(String[] args) {

        // Static input
        int[] arr = {2, 5, 1, 7, 30, 12, 19};
        int n = arr.length;

        // Ascending order (Increment)
        int[] inc = arr.clone();
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                if (inc[i] > inc[j]) {
                    int temp = inc[i];
                    inc[i] = inc[j];
                    inc[j] = temp;
                }
            }
        }

        System.out.print("Increment Order - {");
        for (int i = 0; i < n; i++) {
            System.out.print(inc[i] + (i < n - 1 ? ", " : ""));
        }
        System.out.println("}");

        // Descending order (Decrement)
        int[] dec = arr.clone();
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                if (dec[i] < dec[j]) {
                    int temp = dec[i];
                    dec[i] = dec[j];
                    dec[j] = temp;
                }
            }
        }

        System.out.print("Decrement Order - {");
        for (int i = 0; i < n; i++) {
            System.out.print(dec[i] + (i < n - 1 ? ", " : ""));
        }
        System.out.println("}");
    }
}

